const rows = $input.all().map((item) => item.json);
const control = rows.find((row) => row.kind === 'worklistControl') || rows[0] || {};
const stage = String(control.stage || control.worklistStage || '').trim();
if (!['primarySis', 'relatedSis', 'rec'].includes(stage)) throw new Error(`stage inválido: ${stage}`);
const context = control.context || rows.find((row) => row.context)?.context || {};
const seeds = new Map();
function add(key, role, extra = {}) {
  if (!key || seeds.has(key)) return;
  seeds.set(key, { issueKey:key, role, context, jiraBaseUrl:context.jiraBaseUrl, jiraApiVersion:context.jiraApiVersion, ...extra });
}
if (stage === 'primarySis') {
  for (const row of rows.filter((r)=>r.kind==='commitRecord')) {
    for (const sisKey of row.originSisKeys || []) add(String(sisKey).toUpperCase(), 'primary', { originCommitShas:[row.github?.commit?.sha].filter(Boolean) });
  }
}
if (stage === 'relatedSis') {
  const primary = new Set(rows.filter((r)=>r.kind==='issueRecord' && r.role==='primary').map((r)=>r.issueKey));
  for (const row of rows.filter((r)=>r.kind==='issueRecord' && r.role==='primary')) {
    for (const sisKey of row.issue?.relationships?.relatedSisKeys || []) {
      const key=String(sisKey).toUpperCase(); if (/^SIS-\d+$/.test(key) && !primary.has(key)) add(key,'related',{relatedFrom:[{parentSisKey:row.issueKey,source:'primaryRelationship'}]});
    }
  }
}
if (stage === 'rec') {
  for (const row of rows.filter((r)=>r.kind==='issueRecord' && ['primary','related'].includes(r.role))) {
    for (const recKey of row.issue?.relationships?.recKeys || []) {
      const key=String(recKey).toUpperCase(); if (/^REC-\d+$/.test(key)) add(key,'rec',{relatedFrom:[{parentIssueKey:row.issueKey,source:'issueRelationship'}]});
    }
  }
}
if (!seeds.size) return [{json:{kind:'emptyWorklist',stage,context}}];
return [...seeds.values()].sort((a,b)=>a.issueKey.localeCompare(b.issueKey)).map((seed)=>({json:{kind:'issueSeed',stage,...seed}}));
